const { Document, Packer, Paragraph, TextRun, AlignmentType, HeadingLevel } = require('docx');
const fs = require('fs');

const doc = new Document({
  styles: {
    default: { 
      document: { 
        run: { font: "Calibri", size: 20 } // 10pt base
      } 
    },
    paragraphStyles: [
      {
        id: "Heading1",
        name: "Heading 1",
        basedOn: "Normal",
        next: "Normal",
        quickFormat: true,
        run: { size: 28, bold: true, font: "Calibri" },
        paragraph: { spacing: { before: 0, after: 80 }, outlineLevel: 0 }
      },
      {
        id: "Heading2",
        name: "Heading 2",
        basedOn: "Normal",
        next: "Normal",
        quickFormat: true,
        run: { size: 22, bold: true, font: "Calibri" },
        paragraph: { spacing: { before: 120, after: 60 }, outlineLevel: 1 }
      }
    ]
  },
  numbering: {
    config: [
      {
        reference: "bullets",
        levels: [
          {
            level: 0,
            format: "bullet",
            text: "•",
            alignment: AlignmentType.LEFT,
            style: {
              paragraph: {
                indent: { left: 360, hanging: 240 }
              }
            }
          }
        ]
      }
    ]
  },
  sections: [{
    properties: {
      page: {
        size: {
          width: 12240,
          height: 15840
        },
        margin: { top: 720, right: 720, bottom: 720, left: 720 } // 0.5 inch margins
      }
    },
    children: [
      // Header - Name
      new Paragraph({
        alignment: AlignmentType.CENTER,
        spacing: { after: 40 },
        children: [
          new TextRun({
            text: "SYED ABDUL RAFAY",
            bold: true,
            size: 32, // 16pt
            font: "Calibri"
          })
        ]
      }),

      // Subtitle
      new Paragraph({
        alignment: AlignmentType.CENTER,
        spacing: { after: 40 },
        children: [
          new TextRun({
            text: "Backend Developer | AI & ML Engineer | Software Engineering Student",
            size: 20, // 10pt
            font: "Calibri"
          })
        ]
      }),

      // Contact Info
      new Paragraph({
        alignment: AlignmentType.CENTER,
        spacing: { after: 120 },
        children: [
          new TextRun({
            text: "+92 313 2975559 • sarafay2003@gmail.com • github.com/sarafay2003 • Karachi, Pakistan",
            size: 18, // 9pt
            font: "Calibri"
          })
        ]
      }),

      // Professional Summary
      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [
          new TextRun("PROFESSIONAL SUMMARY")
        ]
      }),

      new Paragraph({
        spacing: { after: 120 },
        children: [
          new TextRun({
            text: "Results-driven final-year Software Engineering student specializing in backend development, RESTful API design, and AI/ML integration. Proficient in Python, C#, and SQL, with demonstrated experience building scalable, database-driven systems and deploying NLP-powered applications. Completed an SQA internship performing API testing and defect lifecycle management. Passionate about clean architecture, system design, and applying machine learning to solve real-world problems.",
            size: 20
          })
        ]
      }),

      // Technical Skills
      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [
          new TextRun("TECHNICAL SKILLS")
        ]
      }),

      new Paragraph({
        spacing: { after: 20 },
        children: [
          new TextRun({ text: "Languages: ", bold: true, size: 20 }),
          new TextRun({ text: "Python, C#, SQL, JavaScript, Bash", size: 20 })
        ]
      }),

      new Paragraph({
        spacing: { after: 20 },
        children: [
          new TextRun({ text: "Backend: ", bold: true, size: 20 }),
          new TextRun({ text: "REST APIs, .NET, Flask, FastAPI, Streamlit, System Design, Microservices", size: 20 })
        ]
      }),

      new Paragraph({
        spacing: { after: 20 },
        children: [
          new TextRun({ text: "AI/ML: ", bold: true, size: 20 }),
          new TextRun({ text: "Machine Learning, NLP, LLMs, Prompt Engineering, RAG Systems, Embeddings, LangChain, Hugging Face, FAISS, scikit-learn, TensorFlow", size: 20 })
        ]
      }),

      new Paragraph({
        spacing: { after: 20 },
        children: [
          new TextRun({ text: "Databases: ", bold: true, size: 20 }),
          new TextRun({ text: "SQL Server, MySQL, SQLite, Database Design, Query Optimization", size: 20 })
        ]
      }),

      new Paragraph({
        spacing: { after: 20 },
        children: [
          new TextRun({ text: "Data: ", bold: true, size: 20 }),
          new TextRun({ text: "Exploratory Data Analysis, Data Visualization, Pandas, NumPy, Matplotlib", size: 20 })
        ]
      }),

      new Paragraph({
        spacing: { after: 20 },
        children: [
          new TextRun({ text: "Testing/QA: ", bold: true, size: 20 }),
          new TextRun({ text: "API Testing, Test Case Design & Execution, Defect Reporting, Regression Testing, Postman", size: 20 })
        ]
      }),

      new Paragraph({
        spacing: { after: 20 },
        children: [
          new TextRun({ text: "Tools: ", bold: true, size: 20 }),
          new TextRun({ text: "Git, GitHub, VS Code, Jupyter Notebook, Visual Studio", size: 20 })
        ]
      }),

      new Paragraph({
        spacing: { after: 120 },
        children: [
          new TextRun({ text: "Soft Skills: ", bold: true, size: 20 }),
          new TextRun({ text: "Analytical Thinking, Attention to Detail, Time Management, Problem-Solving, Team Collaboration", size: 20 })
        ]
      }),

      // Work Experience
      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [
          new TextRun("WORK EXPERIENCE")
        ]
      }),

      new Paragraph({
        spacing: { after: 20 },
        children: [
          new TextRun({ text: "SQA Intern | Paysys Labs Pvt. Ltd.", bold: true, size: 20 }),
          new TextRun({ text: " | Oct 2025 – Jan 2026", size: 20 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 0 },
        children: [
          new TextRun({ text: "Designed and executed comprehensive API test cases to validate backend workflows, request/response payloads, authentication flows, and edge-case handling across multiple microservices.", size: 19 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 0 },
        children: [
          new TextRun({ text: "Identified, documented, and tracked software defects using a structured defect lifecycle process; collaborated with developers to retest fixes and confirm resolution before deployment.", size: 19 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 0 },
        children: [
          new TextRun({ text: "Participated in sprint reviews and regression testing cycles, ensuring quality standards and acceptance criteria were met across all release deployments.", size: 19 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 120 },
        children: [
          new TextRun({ text: "Gained hands-on exposure to Postman for API testing and cross-functional collaboration in an Agile team environment.", size: 19 })
        ]
      }),

      // Projects
      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [
          new TextRun("PROJECTS")
        ]
      }),

      new Paragraph({
        spacing: { after: 20 },
        children: [
          new TextRun({ text: "Payroll Management System API", bold: true, size: 20 }),
          new TextRun({ text: " | Backend Project | 2025", size: 20 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 0 },
        children: [
          new TextRun({ text: "Engineered a RESTful backend API in C# / .NET for end-to-end payroll operations including employee onboarding, attendance tracking, salary computation rules, deductions, and payroll finalization.", size: 19 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 0 },
        children: [
          new TextRun({ text: "Designed a normalized relational database schema in SQL Server with stored procedures and optimized queries to handle large employee datasets efficiently.", size: 19 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 60 },
        children: [
          new TextRun({ text: "Implemented role-based access control and modular architecture to support maintainability and scalability.", size: 19 })
        ]
      }),

      new Paragraph({
        spacing: { after: 20 },
        children: [
          new TextRun({ text: "Medical Report Explainer Chatbot", bold: true, size: 20 }),
          new TextRun({ text: " | AI/NLP Project | 2025", size: 20 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 0 },
        children: [
          new TextRun({ text: "Built a Streamlit web application that simplifies complex medical reports into patient-friendly language using LangChain, Hugging Face transformer models, and FAISS vector search (RAG pipeline).", size: 19 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 0 },
        children: [
          new TextRun({ text: "Applied prompt engineering techniques to fine-tune LLM outputs for medical terminology simplification and context-aware Q&A.", size: 19 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 60 },
        children: [
          new TextRun({ text: "Implemented document ingestion, chunking, embedding generation, and semantic retrieval pipeline from scratch.", size: 19 })
        ]
      }),

      new Paragraph({
        spacing: { after: 20 },
        children: [
          new TextRun({ text: "Python Mobile Security App – Face Recognition", bold: true, size: 20 }),
          new TextRun({ text: " | Computer Vision Project | 2024", size: 20 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 0 },
        children: [
          new TextRun({ text: "Developed a Python-based security application using OpenCV for real-time face detection and recognition via camera input.", size: 19 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 0 },
        children: [
          new TextRun({ text: "Built a backend registration and logging system that records recognized users and flags unknown individuals, providing an audit trail for access control.", size: 19 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 120 },
        children: [
          new TextRun({ text: "Integrated the face recognition pipeline with a SQLite database for persistent user data storage and retrieval.", size: 19 })
        ]
      }),

      // Education
      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [
          new TextRun("EDUCATION")
        ]
      }),

      new Paragraph({
        spacing: { after: 20 },
        children: [
          new TextRun({ text: "Bachelor of Software Engineering", bold: true, size: 20 }),
          new TextRun({ text: " | Bahria University Karachi | Expected Jul 2026", size: 20 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 120 },
        children: [
          new TextRun({ text: "Relevant coursework: Data Structures & Algorithms, Database Systems, Object-Oriented Programming, Software Engineering Principles, Machine Learning, Computer Networks, Operating Systems.", size: 19 })
        ]
      }),

      // Certifications
      new Paragraph({
        heading: HeadingLevel.HEADING_2,
        children: [
          new TextRun("CERTIFICATIONS & ONLINE COURSES")
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 0 },
        children: [
          new TextRun({ text: "Machine Learning Specialization", bold: true, size: 19 }),
          new TextRun({ text: " — Andrew Ng, DeepLearning.AI / Stanford University | Supervised & unsupervised learning, neural networks, recommender systems, reinforcement learning.", size: 19 })
        ]
      }),

      new Paragraph({
        numbering: { reference: "bullets", level: 0 },
        spacing: { after: 0 },
        children: [
          new TextRun({ text: "Generative AI Course", bold: true, size: 19 }),
          new TextRun({ text: " — iCodeGuru | LLMs, prompt engineering, embeddings, RAG systems, and real-world AI application development.", size: 19 })
        ]
      })
    ]
  }]
});

Packer.toBuffer(doc).then(buffer => {
  fs.writeFileSync("/mnt/user-data/outputs/Syed_Abdul_Rafay_Resume_One_Page.docx", buffer);
  console.log("Resume created successfully!");
});

