          numbering: { reference: "bullets", level: 0 },
          spacing: { after: 80 },
          children: [
            new TextRun({ text: "Built AI chatbot to simplify medical terminology using LangChain workflows, FAISS semantic search, and RAG techniques", size: 20 })
          ]
        }),

        // Project 3
        new Paragraph({
          spacing: { after: 40 },
          children: [
            new TextRun({ text: "Mobile Security Application", bold: true, size: 20 }),
            new TextRun({ text: " | Python, OpenCV, Face Recognition API, SQLite", size: 20, italics: true })
          ]
        }),

