const pptxgen = require("pptxgenjs");

let pres = new pptxgen();
pres.layout = 'LAYOUT_16x9';
pres.author = 'Saud Al Faisal, Abdul Rafay, Faisal Wahab';
pres.title = 'Resume Screening & Skill Extraction System';

// Color palette - Professional Tech Theme
const colors = {
  primary: "1E2761",      // Deep navy
  secondary: "0891B2",    // Teal
  accent: "F97316",       // Orange
  light: "F8FAFC",        // Light gray
  text: "1E293B",         // Dark text
  textLight: "64748B"     // Light text
};

// Helper for shadows
const makeShadow = () => ({ 
  type: "outer", 
  blur: 8, 
  offset: 3, 
  angle: 135,
  color: "000000", 
  opacity: 0.12 
});

// ============= SLIDE 1: TITLE SLIDE =============
let slide1 = pres.addSlide();
slide1.background = { color: colors.primary };

slide1.addText("Resume Screening &\nSkill Extraction System", {
  x: 0.5, y: 1.5, w: 9, h: 1.5,
  fontSize: 44, bold: true, color: "FFFFFF",
  align: "center", fontFace: "Arial Black"
});

slide1.addText("Semantic NLP-Powered Recruitment Intelligence", {
  x: 0.5, y: 3.2, w: 9, h: 0.5,
  fontSize: 20, color: "CADCFC", align: "center",
  fontFace: "Arial"
});

slide1.addText("GROUP MEMBERS\nM Saud Al Faisal (02-131222-023)\nSyed Abdul Rafay (02-131222-014)\nFaisal Wahab (02-131222-133)", {
  x: 0.5, y: 4.3, w: 9, h: 0.8,
  fontSize: 14, color: "FFFFFF", align: "center",
  fontFace: "Arial"
});

// ============= SLIDE 2: TABLE OF CONTENTS =============
let slide2 = pres.addSlide();
slide2.background = { color: colors.light };

slide2.addText("Table of Contents", {
  x: 0.5, y: 0.3, w: 9, h: 0.6,
  fontSize: 36, bold: true, color: colors.primary,
  fontFace: "Arial Black"
});

const tocItems = [
  "Introduction & Problem Definition",
  "System Objectives & Requirements",
  "Selected NLP Approach & Justification",
  "System Architecture & Data Flow",
  "AI Interaction & Prompt Engineering",
  "Result Evidence & Performance Analysis",
  "Representative Scenarios",
  "Live System Demonstration",
  "Conclusion & Key Takeaways"
];

let tocY = 1.2;
tocItems.forEach((item, idx) => {
  slide2.addShape(pres.shapes.RECTANGLE, {
    x: 0.8, y: tocY, w: 0.5, h: 0.35,
    fill: { color: colors.secondary }
  });

  slide2.addText((idx + 1).toString(), {
    x: 0.8, y: tocY, w: 0.5, h: 0.35,
    fontSize: 16, bold: true, color: "FFFFFF",
    align: "center", valign: "middle"
  });

  slide2.addText(item, {
    x: 1.5, y: tocY, w: 7.5, h: 0.35,
    fontSize: 14, color: colors.text,
    valign: "middle", fontFace: "Arial"
  });

  tocY += 0.4;
});

// ============= SLIDE 3: INTRODUCTION & PROBLEM DEFINITION =============
let slide3 = pres.addSlide();
slide3.background = { color: "FFFFFF" };

slide3.addText("Introduction & Problem Definition", {
  x: 0.5, y: 0.3, w: 9, h: 0.6,
  fontSize: 36, bold: true, color: colors.primary,
  fontFace: "Arial Black"
});

slide3.addShape(pres.shapes.RECTANGLE, {
  x: 0.5, y: 1.1, w: 4.3, h: 1.8,
  fill: { color: colors.light },
  shadow: makeShadow()
});

slide3.addText("The Traditional Recruitment Bottleneck", {
  x: 0.7, y: 1.25, w: 3.9, h: 0.35,
  fontSize: 16, bold: true, color: colors.primary,
  fontFace: "Arial"
});

slide3.addText("Standard ATS rely on rigid, rule-based keyword matching (Regex) to screen resumes, leading to:", {
  x: 0.7, y: 1.65, w: 3.9, h: 1.0,
  fontSize: 12, color: colors.text,
  fontFace: "Arial"
});

slide3.addShape(pres.shapes.RECTANGLE, {
  x: 5.2, y: 1.1, w: 4.3, h: 1.8,
  fill: { color: colors.light },
  shadow: makeShadow()
});

slide3.addText("The \"Vocabulary Mismatch\" Problem", {
  x: 5.4, y: 1.25, w: 3.9, h: 0.35,
  fontSize: 16, bold: true, color: colors.primary,
  fontFace: "Arial"
});

slide3.addText("Highly qualified candidates rejected for using different terminology (e.g., \"PyTorch\" when ATS searches for \"Machine Learning\")", {
  x: 5.4, y: 1.65, w: 3.9, h: 1.0,
  fontSize: 12, color: colors.text,
  fontFace: "Arial"
});

slide3.addShape(pres.shapes.RECTANGLE, {
  x: 0.5, y: 3.1, w: 4.3, h: 1.8,
  fill: { color: colors.light },
  shadow: makeShadow()
});

slide3.addText("Lack of Contextual Understanding", {
  x: 0.7, y: 3.25, w: 3.9, h: 0.35,
  fontSize: 16, bold: true, color: colors.primary,
  fontFace: "Arial"
});

slide3.addText("Traditional systems cannot distinguish between \"used React for 5 years\" and \"want to learn React\"", {
  x: 0.7, y: 3.65, w: 3.9, h: 1.0,
  fontSize: 12, color: colors.text,
  fontFace: "Arial"
});

slide3.addShape(pres.shapes.RECTANGLE, {
  x: 5.2, y: 3.1, w: 4.3, h: 1.8,
  fill: { color: colors.accent },
  shadow: makeShadow()
});

slide3.addText("The Proposed Solution", {
  x: 5.4, y: 3.25, w: 3.9, h: 0.35,
  fontSize: 16, bold: true, color: "FFFFFF",
  fontFace: "Arial"
});

slide3.addText("Semantic NLP system using advanced language models to comprehend and evaluate resumes based on conceptual meaning", {
  x: 5.4, y: 3.65, w: 3.9, h: 1.0,
  fontSize: 12, color: "FFFFFF",
  fontFace: "Arial"
});

// ============= SLIDE 4: SYSTEM OBJECTIVES & REQUIREMENTS =============
let slide4 = pres.addSlide();
slide4.background = { color: "FFFFFF" };

slide4.addText("System Objectives & Requirements", {
  x: 0.5, y: 0.3, w: 9, h: 0.6,
  fontSize: 36, bold: true, color: colors.primary,
  fontFace: "Arial Black"
});

slide4.addShape(pres.shapes.RECTANGLE, {
  x: 0.5, y: 1.0, w: 9, h: 0.7,
  fill: { color: colors.secondary }
});

slide4.addText("Core Objective", {
  x: 0.7, y: 1.0, w: 8.6, h: 0.7,
  fontSize: 18, bold: true, color: "FFFFFF",
  valign: "middle", fontFace: "Arial"
});

slide4.addText("Develop a fully functional NLP software system that accurately extracts text from PDF resumes, compares it semantically against Job Descriptions, and outputs reliable match scores with constructive feedback.", {
  x: 0.7, y: 1.85, w: 8.6, h: 0.7,
  fontSize: 13, color: colors.text,
  fontFace: "Arial"
});

slide4.addText("Functional Requirements:", {
  x: 0.7, y: 2.7, w: 4, h: 0.4,
  fontSize: 16, bold: true, color: colors.primary,
  fontFace: "Arial"
});

const functionalReqs = [
  "Data Ingestion: Extract raw text from unstructured PDF documents",
  "Semantic Matching: Map candidate skills to job requirements contextually",
  "Structured Output: Return predictable, strictly formatted JSON data"
];

let reqY = 3.15;
functionalReqs.forEach(req => {
  slide4.addText("•", {
    x: 0.9, y: reqY, w: 0.2, h: 0.3,
    fontSize: 14, color: colors.secondary, bold: true
  });

  slide4.addText(req, {
    x: 1.2, y: reqY, w: 8, h: 0.3,
    fontSize: 12, color: colors.text,
    fontFace: "Arial"
  });

  reqY += 0.35;
});

slide4.addText("Non-Functional Requirements:", {
  x: 0.7, y: 4.3, w: 4, h: 0.4,
  fontSize: 16, bold: true, color: colors.primary,
  fontFace: "Arial"
});

slide4.addText("Low latency (fast processing) • Robust error handling • High availability", {
  x: 0.9, y: 4.75, w: 8, h: 0.3,
  fontSize: 12, color: colors.text,
  fontFace: "Arial"
});

// ============= SLIDE 5: NLP APPROACH & JUSTIFICATION =============
let slide5 = pres.addSlide();
slide5.background = { color: "FFFFFF" };

slide5.addText("Selected NLP Approach & Justification", {
  x: 0.5, y: 0.3, w: 9, h: 0.6,
  fontSize: 36, bold: true, color: colors.primary,
  fontFace: "Arial Black"
});

slide5.addShape(pres.shapes.RECTANGLE, {
  x: 0.5, y: 1.1, w: 4.3, h: 1.5,
  fill: { color: colors.light },
  shadow: makeShadow()
});

slide5.addText("❌ Why Not Basic Regex or TF-IDF?", {
  x: 0.7, y: 1.25, w: 3.9, h: 0.35,
  fontSize: 15, bold: true, color: colors.primary,
  fontFace: "Arial"
});

slide5.addText("Simple word-frequency models (TF-IDF) or NER cannot understand relationships between tech stacks or context", {
  x: 0.7, y: 1.65, w: 3.9, h: 0.8,
  fontSize: 12, color: colors.text,
  fontFace: "Arial"
});

slide5.addShape(pres.shapes.RECTANGLE, {
  x: 5.2, y: 1.1, w: 4.3, h: 1.5,
  fill: { color: colors.secondary },
  shadow: makeShadow()
});

slide5.addText("✓ The Selected Approach", {
  x: 5.4, y: 1.25, w: 3.9, h: 0.35,
  fontSize: 15, bold: true, color: "FFFFFF",
  fontFace: "Arial"
});

slide5.addText("Large Language Models (LLMs) with advanced Prompt Engineering (GPT-4o-mini)", {
  x: 5.4, y: 1.65, w: 3.9, h: 0.8,
  fontSize: 12, color: "FFFFFF",
  fontFace: "Arial"
});

slide5.addText("Justification for LLM Approach", {
  x: 0.5, y: 2.9, w: 9, h: 0.4,
  fontSize: 18, bold: true, color: colors.primary,
  fontFace: "Arial"
});

const justifications = [
  {
    title: "Semantic Reasoning",
    desc: "LLMs understand tech ecosystems and can deduce that a \"MERN stack\" developer satisfies requirements for MongoDB, Express, React, and Node"
  },
