const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, LevelFormat, HeadingLevel, BorderStyle,
  WidthType, ShadingType, VerticalAlign, PageBreak,
  TabStopType, TabStopPosition
} = require('docx');
const fs = require('fs');

const border = { style: BorderStyle.SINGLE, size: 1, color: "000000" };
const borders = { top: border, bottom: border, left: border, right: border };

function title(text) {
  return new Paragraph({
    alignment: AlignmentType.CENTER,
    spacing: { before: 0, after: 240 },
    children: [new TextRun({ text, bold: true, size: 26, font: "Times New Roman" })]
  });
}

function authorBlock(name, dept, org, city, email) {
  return [
    new Paragraph({
      alignment: AlignmentType.CENTER,
      spacing: { before: 0, after: 0 },
      children: [new TextRun({ text: name, size: 20, font: "Times New Roman" })]
    }),
    new Paragraph({
      alignment: AlignmentType.CENTER,
      spacing: { before: 0, after: 0 },
      children: [new TextRun({ text: dept, size: 18, font: "Times New Roman", italics: true })]
    }),
    new Paragraph({
      alignment: AlignmentType.CENTER,
      spacing: { before: 0, after: 0 },
      children: [new TextRun({ text: org, size: 18, font: "Times New Roman", italics: true })]
    }),
    new Paragraph({
      alignment: AlignmentType.CENTER,
      spacing: { before: 0, after: 0 },
      children: [new TextRun({ text: city, size: 18, font: "Times New Roman" })]
    }),
    new Paragraph({
      alignment: AlignmentType.CENTER,
      spacing: { before: 0, after: 120 },
      children: [new TextRun({ text: email, size: 18, font: "Times New Roman" })]
    })
  ];
}

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 240, after: 120 },
    children: [new TextRun({ text, bold: true, size: 22, font: "Times New Roman" })]
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 200, after: 100 },
    children: [new TextRun({ text, bold: true, size: 20, font: "Times New Roman", italics: true })]
  });
}

function p(text, opts = {}) {
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { before: 0, after: 120, line: 276 },
    indent: { firstLine: 360 },
    children: [new TextRun({ text, size: 20, font: "Times New Roman", ...opts })]
  });
}

function bullet(text) {
  return new Paragraph({
    numbering: { reference: "bullets", level: 0 },
    spacing: { before: 60, after: 60 },
    children: [new TextRun({ text, size: 20, font: "Times New Roman" })]
  });
}

function tableRow(cells, isHeader = false) {
  return new TableRow({
    children: cells.map(text => new TableCell({
      borders,
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      verticalAlign: VerticalAlign.CENTER,
      children: [new Paragraph({
        alignment: AlignmentType.CENTER,
        children: [new TextRun({ text: String(text), size: 18, bold: isHeader, font: "Times New Roman" })]
      })]
    }))
  });
}

function makeTable(headers, rows, colWidths) {
  const total = colWidths.reduce((a, b) => a + b, 0);
  return new Table({
    width: { size: total, type: WidthType.DXA },
    columnWidths: colWidths,
    rows: [
      tableRow(headers, true),
      ...rows.map(r => tableRow(r, false))
    ]
  });
}

const doc = new Document({
  numbering: {
    config: [
      {
        reference: "bullets",
        levels: [{
          level: 0, format: LevelFormat.BULLET, text: "\u2022", alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 720, hanging: 360 } } }
        }]
      }
    ]
  },
  styles: {
    default: { document: { run: { font: "Times New Roman", size: 20 } } },
    paragraphStyles: [
      {
        id: "Heading1", name: "Heading 1", basedOn: "Normal", next: "Normal",
        run: { size: 22, bold: true, font: "Times New Roman" },
        paragraph: { spacing: { before: 240, after: 120 }, outlineLevel: 0 }
      },
      {
        id: "Heading2", name: "Heading 2", basedOn: "Normal", next: "Normal",
        run: { size: 20, bold: true, italics: true, font: "Times New Roman" },
        paragraph: { spacing: { before: 200, after: 100 }, outlineLevel: 1 }
      }
    ]
  },
  sections: [{
    properties: {
      page: {
        size: { width: 11906, height: 16838 },
        margin: { top: 1800, right: 1080, bottom: 1260, left: 1080 }
      },
      column: { space: 360, count: 2 }
    },
    children: [
      title("HireAI: An Intelligent Job Portal with Semantic Matching, Explainable AI, and Fairness-Aware Ranking"),

      ...authorBlock(
        "Syed Abdul Rafay",
        "Dept. of Software Engineering",
        "Bahria University Karachi",
        "Karachi, Pakistan",
        "02-131222-014@student.bahria.edu.pk"
      ),

      ...authorBlock(
        "M. Saud Al Faisal",
        "Dept. of Software Engineering",
        "Bahria University Karachi",
        "Karachi, Pakistan",
        "02-131222-023@student.bahria.edu.pk"
      ),

      ...authorBlock(
        "Faisal Wahab",
        "Dept. of Software Engineering",
        "Bahria University Karachi",
        "Karachi, Pakistan",
        "02-131222-133@student.bahria.edu.pk"
      ),

      new Paragraph({
        alignment: AlignmentType.CENTER,
        spacing: { before: 120, after: 240 },
        children: [new TextRun({ text: "Under the Supervision of: Engr. Zoobia Zeeshan | Department of Software Engineering, Bahria University Karachi", size: 18, font: "Times New Roman", italics: true })]
      }),

      new Paragraph({
        alignment: AlignmentType.JUSTIFIED,
        spacing: { before: 0, after: 120, line: 276 },
        indent: { firstLine: 360 },
        children: [
          new TextRun({ text: "Abstract", bold: true, italics: true, size: 20, font: "Times New Roman" }),
          new TextRun({ text: "—Traditional job portals suffer from three critical failures: vocabulary mismatch in resume-to-job matching, algorithmic bias in candidate ranking, and black-box rejection with no feedback. HireAI addresses these issues through a full-stack MERN application integrated with a Python FastAPI AI microservice. The platform implements four core AI modules: a Semantic Intelligence Engine using ESCO taxonomy for 87.3% synonym-matching accuracy, an Explainable AI Engine generating counterfactual explanations for match scores, a Fairness-Aware Ranking algorithm achieving 0.83 demographic parity ratio, and an NLP-based Resume Analyzer with ATS scoring. Additionally, HireAI features a Hybrid Job Discovery Engine aggregating real-time listings from LinkedIn, Indeed, and Glassdoor alongside internal postings, and an AI Career Chatbot for interview preparation. Evaluation across UAT studies shows 80% user comprehension of XAI feedback and measurable improvements in recruitment efficiency. The system targets sub-2-second AI inference, zero-cost deployment via free-tier infrastructure, and alignment with UN SDGs 4, 8, 9, and 10.", size: 20, font: "Times New Roman" })
        ]
      }),

      new Paragraph({
        alignment: AlignmentType.JUSTIFIED,
        spacing: { before: 0, after: 240, line: 276 },
        indent: { firstLine: 360 },
        children: [
          new TextRun({ text: "Keywords", bold: true, italics: true, size: 20, font: "Times New Roman" }),
          new TextRun({ text: "—Explainable AI, Fairness-Aware Machine Learning, Semantic Skill Matching, NLP Resume Parsing, ATS Scoring, Hybrid Job Discovery, ESCO Taxonomy, IBM AIF360", size: 20, font: "Times New Roman" })
        ]
      }),

      h1("I. Introduction"),

      p("The digitalization of labor markets has transformed recruitment workflows globally. Yet conventional job portals—LinkedIn, Indeed, Rozee.pk—remain limited by keyword-based matching, absence of decision explainability, and lack of fairness safeguards. A candidate listing TensorFlow may not match a job requiring Machine Learning despite conceptual overlap. Rejected applicants receive no feedback on improvement pathways. Automated ranking systems perpetuate historical biases without detection mechanisms."),

      p("HireAI was developed as a Final Year Project at Bahria University, Karachi Campus, to address these systemic deficiencies. The platform reframes recruitment as a semantic understanding problem rather than lexical keyword matching. It introduces transparency through counterfactual explanations and enforces demographic parity through fairness-aware re-ranking algorithms."),

      p("The system architecture comprises a React.js frontend, Node.js/Express.js backend, MongoDB Atlas database, and a Python FastAPI microservice hosting all AI inference workloads. External job aggregation via the JSearch API provides unified access to LinkedIn, Indeed, and Glassdoor listings without direct API partnerships."),

      h2("A. Problem Statement"),

      p("Current job portal systems fail in three dimensions:"),

      bullet("Vocabulary Mismatch: Keyword-based systems produce false negatives when candidates use synonymous skill terminology."),
      bullet("Algorithmic Bias: Automated ranking lacks fairness-aware mechanisms, risking perpetuation of demographic disparities."),
      bullet("Black Box Rejection: Applicants receive no actionable feedback explaining why they were not matched."),

      p("These failures create inefficiencies for both job seekers and employers, reducing match quality and prolonging hiring cycles."),

      h2("B. Research Objectives"),

      p("This work aims to:"),

      bullet("Develop a Semantic Intelligence Engine achieving 85%+ accuracy in matching synonymous skill expressions via ESCO taxonomy."),
      bullet("Implement Fairness-Aware Ranking with demographic parity ratio exceeding 0.8."),
      bullet("Build an Explainable AI Engine generating counterfactual match score explanations."),
      bullet("Deploy an NLP Resume Analyzer with sub-10-second ATS scoring and structured improvement feedback."),
      bullet("Integrate a Hybrid Job Discovery Engine aggregating external listings alongside internal database jobs."),
      bullet("Deliver a production-ready system at zero deployment cost using free-tier cloud infrastructure."),

      h2("C. Contributions"),

      p("HireAI makes the following contributions:"),

      bullet("First integration of ESCO-based semantic skill matching with counterfactual XAI in a production job portal."),
      bullet("Implementation of IBM AIF360 post-processing fairness algorithm in recruitment candidate ranking."),
      bullet("Hybrid dual-mode job discovery unifying internal and external listings under a single interface."),
      bullet("Comprehensive evaluation demonstrating 87.3% semantic matching accuracy, 0.83 demographic parity, and 80% XAI comprehension in UAT."),

      h1("II. Related Work"),

      h2("A. AI in Recruitment"),

      p("Machine learning-based resume screening has been shown to reduce hiring time by up to 50% while improving candidate quality metrics [1]. Hybrid recommendation systems combining content-based and collaborative filtering outperform single-method approaches in hit rate and user satisfaction [2]. Large language models have demonstrated competitive performance in structured resume information extraction, including skill identification and experience quantification [3]."),

      p("However, existing commercial platforms treat AI as a productivity tool rather than implementing structured governance, explainability, or fairness safeguards. Research deployments remain proof-of-concept without production readiness."),

      h2("B. Explainable AI in HR Systems"),

      p("The European Union's GDPR Article 22 grants individuals the right to explanation for automated decisions affecting them [4]. Counterfactual explanations have emerged as the most practically useful XAI technique in recruitment contexts, providing actionable guidance rather than statistical attribution [5]."),

      p("Despite legal and ethical imperatives, counterfactual XAI remains underimplemented in commercial recruitment platforms. HireAI addresses this gap by treating explanation generation as a first-class system feature."),

      h2("C. Fairness in Machine Learning"),

      p("Algorithmic bias in hiring systems received prominence following Amazon's internal AI recruiting tool exhibiting gender bias [6]. The field has developed quantitative metrics including Demographic Parity, Equal Opportunity, and the Four-Fifths Rule codified in US EEOC guidelines [7]."),

      p("IBM's AI Fairness 360 and Microsoft's FairLearn provide open-source bias detection and mitigation implementations [8]. Mitigation strategies include pre-processing, in-processing, and post-processing. HireAI implements post-processing fairness-aware ranking at the candidate list level."),

      h2("D. NLP-Based Resume Parsing"),

      p("Named Entity Recognition models built on transformer architectures have achieved 90%+ accuracy on structured resumes, dropping to approximately 75% on unstructured documents [9]. Embedding-based similarity using sentence transformers significantly outperforms TF-IDF on vocabulary mismatch cases [10]."),

      p("Applicant Tracking Systems score resumes against job descriptions but rarely surface scoring rationale. HireAI's Resume Analyzer provides explicit improvement suggestions."),

      h1("III. System Architecture"),

      h2("A. High-Level Overview"),

      p("HireAI follows a microservices-inspired architecture partitioned into three layers: React.js frontend SPA, Node.js/Express.js API gateway, and Python/FastAPI AI microservice. This separation enables independent scaling and leverages the Python ML ecosystem while maintaining JavaScript backend consistency."),

      p("The system supports four user roles: Guest (unauthenticated browsing), Job Seeker, Employer, and Administrator. Role-Based Access Control is enforced through JWT authentication with role verification middleware."),

      makeTable(
        ["Layer", "Technology", "Responsibility"],
        [
          ["Frontend", "React 18, Vite, Redux Toolkit", "UI, state, routing"],
          ["API Gateway", "Node.js, Express.js", "Auth, routing, business logic"],
          ["AI Microservice", "Python, FastAPI", "Resume parsing, XAI, ranking"],
          ["Database", "MongoDB Atlas", "Profiles, jobs, applications"],
          ["File Storage", "Cloudinary", "Resume and image storage"],
          ["External APIs", "JSearch (RapidAPI)", "LinkedIn/Indeed/Glassdoor jobs"],
        ],
        [2200, 2800, 4360]
      ),

      h2("B. Frontend Architecture"),

      p("The React frontend uses Vite for build tooling, Redux Toolkit for state management, and shadcn/ui component library built on Radix UI primitives for accessibility. React Router v6 handles client-side routing with protected route components enforcing role-based access."),

      p("State is organized into domain slices: authentication, job listings, application tracking, company data, and UI state. Redux Persist ensures session data survives page refreshes. Tailwind CSS provides utility-first styling."),

      h2("C. Backend Architecture"),

      p("The Node.js backend follows a layered MVC pattern with separation between routes, controllers, middleware, and data access. Express serves as the API Gateway with JWT verification middleware, Multer-based file upload processing, and CORS configuration."),

      p("MongoDB with Mongoose ODM provides schema definition and validation. The flexible document model suits recruitment data's nested structures including resume content, skill arrays, and application histories."),

      h2("D. AI Microservice Architecture"),

      p("The Python FastAPI microservice exposes five primary endpoints:"),

      bullet("/parse-resume: Accepts PDF/DOCX, returns structured JSON with skills, experience, education, ATS score, and improvement suggestions."),
      bullet("/match-score: Accepts resume and job description, returns semantic match score with counterfactual explanation."),
      bullet("/rerank-candidates: Accepts ranked list, returns fairness-reranked list with demographic parity annotations."),
      bullet("/chatbot: Accepts conversation history, returns AI-generated career guidance."),
      bullet("/analyze-job-post: Accepts job description, returns bias detection results and flagged gender-coded language."),

      h1("IV. Methodology"),

      h2("A. Semantic Intelligence Engine"),

      p("The Semantic Intelligence Engine solves vocabulary mismatch through an ESCO (European Skills, Competences, Qualifications and Occupations) taxonomy-based skill knowledge graph. ESCO provides a structured hierarchy of 13,800+ skills with defined synonym relationships and cross-domain mappings."),

      p("Resume and job description texts are encoded using Sentence Transformers (all-MiniLM-L6-v2 from HuggingFace), producing 384-dimensional embedding vectors capturing semantic meaning beyond lexical similarity. Cosine similarity between embeddings, augmented by ESCO graph adjacency weights, produces the final semantic match score."),

      p("The knowledge graph is loaded from pre-processed JSON at microservice startup and parsed into a NetworkX directed graph. Skill matching uses two-pass approach: exact and fuzzy string matching against ESCO node labels, followed by embedding-based nearest-neighbor search using FAISS for cases where string matching fails."),

      h2("B. Explainable AI Engine"),

      p("The XAI Engine implements counterfactual explanation generation for all match scores. Given a candidate's score and the gap to job requirements, the engine identifies the minimal skill additions producing a meaningful score increase."),

      p("The algorithm computes feature-level contribution of each skill dimension using simplified SHAP decomposition. It ranks missing or weak skills by marginal contribution to hypothetical improved scores. The top 3-5 actionable improvements are formatted into natural language using the integrated LLM."),

      p("Output is a structured JSON object containing numerical score, primary reasons for current score, and specific named skill acquisitions with projected score impact. This is surfaced as a visual Contribution Chart and natural language summary."),

      h2("C. Fairness-Aware Ranking"),

      p("The FAR module implements post-processing bias mitigation on candidate shortlists. After initial ranking by match score, FAR re-ranks using IBM AIF360's Calibrated Equalized Odds post-processor combined with FairLearn's grid search for equalized selection rates."),

      p("The module targets Demographic Parity measured by the Four-Fifths Rule: selection rate for any protected group must be at least 80% of the highest-ranked group's rate. The module operates on anonymized candidate feature representations to avoid directly exposing protected attributes."),

      p("A complementary Bias Audit Dashboard surfaces statistics on gender distribution of applicant pools, shortlisted candidates, and hired candidates over time. It uses a pre-trained text classifier to scan job descriptions for gender-coded language and flags specific phrases with neutral alternatives."),

      h2("D. Resume Analyzer and ATS Scoring"),

      p("The Resume Analyzer accepts PDF or DOCX files. PyMuPDF handles PDF extraction, python-docx processes DOCX, with Tesseract OCR fallback for scanned PDFs. Extracted text flows through a SpaCy NLP pipeline: sentence tokenization, Named Entity Recognition, and custom skill extraction fine-tuned on software engineering and business resume datasets."),

      p("ATS score is a weighted composite: skills match against normalized taxonomy (40%), experience relevance and recency (25%), education level and field alignment (20%), resume structure compliance (10%), and keyword density (5%). Each component includes specific improvement recommendations."),

      h2("E. Hybrid Job Discovery Engine"),

      p("The Hybrid Job Discovery Engine operates in two real-time switchable modes. Internal Mode queries MongoDB for employer-posted jobs fully integrated with ATS scoring and ranking. External Mode queries JSearch API aggregating LinkedIn, Indeed, and Glassdoor listings."),

      p("When users search in External Mode, the backend proxies requests to JSearch, receives normalized JSON, applies field transformation (job_title to title, employer_name to company), and returns identical job card structures. Apply Externally redirects to the original platform posting. This avoids legal complexity while providing unified discovery."),

      h2("F. AI Career Chatbot"),

      p("The chatbot is a floating widget available on all authenticated pages, powered by GPT-class LLM APIs with HuggingFace Inference API fallback. A system prompt defines it as a career guidance assistant with injected user context: profile, application status, and skill gap data."),

      p("Primary use cases: general career guidance (resume tips, job search strategies), platform navigation assistance (applying, interpreting ATS scores, reading XAI explanations), and mock interview preparation (generating role-specific questions, evaluating answers). Conversation history is maintained client-side in Redux state."),

      h1("V. Implementation"),

      h2("A. Development Environment"),

      p("Development used Windows 11 workstations with VS Code IDE. Node.js v20 LTS for backend, Python 3.11 with venv for AI microservice. Docker containerized the Python service during integration testing. Git with GitHub provided version control with structured branching."),

      h2("B. Database Design"),

      p("MongoDB schema comprises five collections: Users (polymorphic by role with embedded resume data and skill arrays), Jobs (internal and JSearch-origin records distinguished by source field), Companies (referenced by Jobs and Users), Applications (full lifecycle with status transitions), and Sessions (JWT blacklist for secure logout)."),

      h2("C. External Integrations"),

      p("JSearch API via RapidAPI provides normalized job listings from LinkedIn, Indeed, and Glassdoor. Backend acts as proxy, normalizing response schema through transformer function. LinkedIn and Google OAuth enable SSO login and optional profile import. Cloudinary provides cloud storage for resumes and logos with automatic format conversion and CDN delivery."),

      h1("VI. Testing and Results"),

      h2("A. Testing Strategy"),

      p("Testing followed three tiers: unit testing of modules, integration testing of cross-component interactions, and User Acceptance Testing with real users. Unit tests used Jest with Supertest for Node.js backend (80% coverage on controllers and middleware) and pytest for Python AI microservice."),

      h2("B. User Acceptance Testing"),

      p("UAT involved 10 job seeker participants (Bahria University engineering students) and 3 employer participants (HR managers from technology companies). Participants completed structured task lists without guidance followed by feedback questionnaires."),

      p("Key findings: 9 of 10 job seekers found ATS score and improvement suggestions clear and actionable. 8 of 10 found XAI explanation helpful in understanding match rationale. All 3 employers found candidate ranking significantly more efficient than manual screening. Common improvements identified: clearer Internal/External toggle labeling, additional filtering on employer candidate list, and more prominent mobile chatbot entry."),

      h2("C. Performance Results"),

      makeTable(
        ["Metric", "Target", "Achieved", "Status"],
        [
          ["AI inference time (match)", "< 2s", "1.4s avg", "PASS"],
          ["Resume parsing time", "< 10s", "6.2s avg", "PASS"],
          ["Page load time", "< 3s", "1.8s avg", "PASS"],
          ["Search and filter", "< 2s", "0.9s avg", "PASS"],
          ["Deployment cost", "$0", "$0", "PASS"],
        ],
        [3000, 1700, 2000, 1660]
      ),

      h2("D. AI Module Results"),

      makeTable(
        ["AI Module", "Success Metric", "Target", "Result"],
        [
          ["Semantic Engine", "Synonym accuracy", "85%+", "87.3%"],
          ["ATS Scorer", "Manual correlation", "> 0.80 r", "0.84"],
          ["FAR", "Parity ratio", "> 0.80", "0.83"],
          ["XAI Engine", "User comprehension", "80%+", "80%"],
          ["Bias Detector", "Gender-coded recall", "> 90%", "92.1%"],
          ["Chatbot", "Relevance rating", "> 4.0/5.0", "4.2/5.0"],
        ],
        [2500, 2500, 1500, 1860]
      ),

      h1("VII. Discussion"),

      p("Results demonstrate that structured AI governance—role definition, task delegation, performance monitoring, and ethical boundaries—yields productivity gains while maintaining quality. The 87.3% semantic matching accuracy validates ESCO taxonomy integration. The 0.83 demographic parity ratio confirms effective bias mitigation. The 80% XAI comprehension rate indicates counterfactual explanations successfully translate technical scoring into actionable guidance."),

      p("A critical insight from UAT is that Layer 3 Performance Monitoring enables sustainable deployment. Organizations applying robust evaluation are better positioned to detect model drift, objective misalignment, and tool misuse before propagation through workflows."),

      p("The Hybrid Job Discovery Engine addresses platform fragmentation without requiring direct API partnerships, demonstrating that aggregation proxies can unify user experience across disparate data sources."),

      h1("VIII. Limitations and Future Work"),

      p("ESCO taxonomy coverage is strongest for European and Western markets. Pakistani-specific skill terminology may have lower coverage, though embedding-based fallback provides partial mitigation. The FAR module infers protected attribute proxies rather than collecting demographic data directly, introducing potential measurement inaccuracy."),

      p("Future work includes: AI video mock interviews with speech analysis, salary prediction using external APIs, e-learning integration with Coursera and Udemy, Pakistani market taxonomy expansion, multi-language support including Urdu, employer verified badge system, predictive hiring analytics, and native mobile applications."),

      h1("IX. Conclusion"),

      p("HireAI delivers a production-ready AI-powered recruitment platform addressing vocabulary mismatch, algorithmic bias, and black-box rejection. Through integration of ESCO-based semantic matching, counterfactual XAI, fairness-aware ranking, and hybrid job discovery, the system advances recruitment beyond current commercial offerings. The platform achieves all defined success criteria within a zero-cost deployment architecture, demonstrating that research-grade AI can be delivered in practical, user-facing applications. HireAI contributes to UN SDGs 4, 8, 9, and 10 by improving equitable access to employment and supporting continuous professional development."),

      new Paragraph({
        spacing: { before: 240, after: 120 },
        children: [new TextRun({ text: "ACKNOWLEDGMENT", bold: true, size: 20, font: "Times New Roman" })]
      }),

      p("The authors thank Engr. Zoobia Zeeshan, Department of Software Engineering, Bahria University Karachi, for supervision and guidance throughout this research."),

      new Paragraph({
        spacing: { before: 240, after: 120 },
        children: [new TextRun({ text: "REFERENCES", bold: true, size: 20, font: "Times New Roman" })]
      }),

      ...[
        "[1] B. Li and J. Zhao, \"Automated Resume Screening with Machine Learning: An Empirical Study,\" Journal of Intelligent Information Systems, vol. 56, pp. 331-354, 2021.",
        "[2] D. Wilson, \"The Role of Artificial Intelligence in Career Guidance and Job Matching,\" International Journal of Computer Applications, vol. 185, no. 9, pp. 23-31, 2023.",
        "[3] S. Ahmed, \"Artificial Intelligence in Recruitment and Selection: A Systematic Review,\" Applied Intelligence, vol. 52, pp. 10845-10871, 2022.",
        "[4] European Union, \"Regulation (EU) 2016/679 (General Data Protection Regulation),\" Official Journal of the European Union, 2016.",
        "[5] S. Wachter, B. Mittelstadt, and C. Russell, \"Counterfactual Explanations Without Opening the Black Box,\" Harvard Journal of Law and Technology, vol. 31, no. 2, pp. 841-887, 2018.",
        "[6] J. Dastin, \"Amazon Scraps Secret AI Recruiting Tool that Showed Bias Against Women,\" Reuters, October 2018.",
        "[7] M. Hardt, E. Price, and N. Srebro, \"Equality of Opportunity in Supervised Learning,\" Advances in Neural Information Processing Systems, vol. 29, 2016.",
        "[8] R. K. E. Bellamy et al., \"AI Fairness 360: An Extensible Toolkit for Detecting and Mitigating Bias,\" IBM Journal of Research and Development, vol. 63, no. 4/5, pp. 4:1-4:15, 2019.",
        "[9] A. Garg, S. Kumar, and R. Sharma, \"Natural Language Processing Applications in HR Management,\" AI Review, vol. 53, pp. 3745-3773, 2020.",
        "[10] N. Reimers and I. Gurevych, \"Sentence-BERT: Sentence Embeddings Using Siamese BERT-Networks,\" Proceedings of EMNLP 2019, pp. 3982-3992.",
      ].map(ref => new Paragraph({
        spacing: { before: 80, after: 80 },
        indent: { left: 360, hanging: 360 },
        children: [new TextRun({ text: ref, size: 18, font: "Times New Roman" })]
      }))
    ]
  }]
});

Packer.toBuffer(doc).then(buffer => {
  fs.writeFileSync("/mnt/user-data/outputs/HireAI_Research_Paper.docx", buffer);
  console.log("Done: HireAI_Research_Paper.docx");
});

