        h3("4.14.1 Component: Semantic Intelligence Engine"),

        p("Purpose: Compute semantic match scores between candidate resumes and job descriptions accounting for vocabulary mismatch through ESCO taxonomy knowledge graph."),

        p("Inputs:"),
        bullet("Candidate resume text (string)"),
        bullet("Job description text (string)"),
        bullet("Candidate skill list (array of strings)"),
        bullet("Required skill list from job (array of strings)"),

        p("Processing:"),
        numbered("Load ESCO skill knowledge graph from JSON file into NetworkX directed graph"),
        numbered("Extract skills from resume and job description using custom skill matcher"),
        numbered("Encode resume text and job description using Sentence Transformers (all-MiniLM-L6-v2) to produce 384-dimensional embeddings"),
        numbered("Compute cosine similarity between resume and job embeddings"),
        numbered("For each skill in resume, traverse ESCO graph to find synonymous or hierarchically related skills in job requirements"),
        numbered("Compute skill overlap score accounting for ESCO graph adjacency weights"),
        numbered("Combine embedding similarity (60%) and skill overlap score (40%) into final match score"),

        p("Outputs:"),
        bullet("Match score (0-100 percentage)"),
        bullet("Matched skills (array of {resume_skill, job_skill, similarity} objects)"),
        bullet("Missing skills (array of strings)"),
        bullet("Inference time (milliseconds)"),

        p("Performance Constraints:"),
        bullet("Target inference time: <2 seconds"),
        bullet("Accuracy target: >85% on synonym matching test cases"),

        h3("4.14.2 Component: Explainable AI (XAI) Engine"),

        p("Purpose: Generate counterfactual explanations for match scores identifying specific skill acquisitions that would improve score."),

        p("Inputs:"),
        bullet("Current match score (float 0-100)"),
        bullet("Matched skills (array)"),
        bullet("Missing skills (array)"),
        bullet("Job requirements (object)"),

        p("Processing:"),
        numbered("Compute feature-level contribution of each skill dimension using simplified SHAP decomposition"),
        numbered("Rank missing skills by marginal score contribution (how much score would increase if skill were present)"),
        numbered("Select top 3-5 highest-impact missing skills"),
        numbered("For each selected skill, compute projected score increase using counterfactual simulation"),
        numbered("Generate natural language explanation using LLM with structured prompt template"),

        p("Outputs:"),
        bullet("Counterfactual explanation (string)"),
        bullet("Skill recommendations (array of {skill, projected_increase} objects)"),
        bullet("Visual contribution breakdown (JSON for frontend charting)"),

        p("Performance Constraints:"),
        bullet("Explanation generation time: <1 second"),
        bullet("User comprehension target: >80% in UAT"),

        h3("4.14.3 Component: Fairness-Aware Ranking Module"),

        p("Purpose: Re-rank candidate shortlists to ensure demographic parity, preventing algorithmic bias in candidate selection."),

        p("Inputs:"),
        bullet("Ranked candidate list (array of candidate objects with match scores)"),
        bullet("Protected attribute proxy indicators (inferred from profile data)"),
        bullet("Target demographic parity ratio (default 0.80)"),

        p("Processing:"),
        numbered("Anonymize candidate features, removing direct identifiers"),
        numbered("Infer protected attribute proxies from remaining features"),
        numbered("Compute current demographic parity ratio (selection rate for protected group / selection rate for majority group)"),
        numbered("If ratio < 0.80, apply IBM AIF360 Calibrated Equalized Odds post-processor"),
        numbered("Re-rank candidates using FairLearn grid search optimizing for demographic parity"),
        numbered("Validate new ranking achieves target parity ratio"),
        numbered("Generate demographic distribution statistics"),

        p("Outputs:"),
        bullet("Re-ranked candidate list (array preserving match scores but adjusted order)"),
        bullet("Demographic parity ratio (float)"),
        bullet("Distribution statistics (object with group counts and selection rates)"),
        bullet("Bias flags (array of detected issues)"),

