const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, BorderStyle, WidthType, ShadingType, HeadingLevel,
  UnderlineType
} = require('docx');
const fs = require('fs');

const border = { style: BorderStyle.SINGLE, size: 4, color: "000000" };
const borders = { top: border, bottom: border, left: border, right: border };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

function heading(text) {
  return new Paragraph({
    spacing: { before: 200, after: 100 },
    children: [new TextRun({ text, bold: true, underline: { type: UnderlineType.SINGLE }, size: 24, font: "Times New Roman" })]
  });
}

function para(text, options = {}) {
  return new Paragraph({
    spacing: { before: 80, after: 80 },
    children: [new TextRun({ text, size: 24, font: "Times New Roman", ...options })]
  });
}

function mathLine(text) {
  return new Paragraph({
    spacing: { before: 60, after: 60 },
    indent: { left: 360 },
    children: [new TextRun({ text, size: 24, font: "Times New Roman" })]
  });
}

function makeRow(cells, isHeader = false) {
  return new TableRow({
    children: cells.map((cell, i) => new TableCell({
      borders,
      width: { size: cell.w || 1500, type: WidthType.DXA },
      shading: isHeader ? { fill: "CCCCCC", type: ShadingType.CLEAR } : { fill: "FFFFFF", type: ShadingType.CLEAR },
      margins: { top: 60, bottom: 60, left: 100, right: 100 },
      children: [new Paragraph({
        alignment: cell.center ? AlignmentType.CENTER : AlignmentType.LEFT,
        children: [new TextRun({ text: String(cell.text), bold: isHeader || cell.bold, size: 22, font: "Times New Roman" })]
      })]
    }))
  });
}

// Simplex tableau rows
function simplexRow(cells) {
  return new TableRow({
    children: cells.map(cell => new TableCell({
      borders,
      width: { size: cell.w || 800, type: WidthType.DXA },
      shading: { fill: cell.shade || "FFFFFF", type: ShadingType.CLEAR },
      margins: { top: 40, bottom: 40, left: 60, right: 60 },
      children: [new Paragraph({
        alignment: AlignmentType.CENTER,
        children: [new TextRun({ text: String(cell.text), bold: cell.bold, size: 18, font: "Times New Roman" })]
      })]
    }))
  });
}

const varCols = ['x\u2081', 'x\u2082', 'x\u2083', 's\u2081', 's\u2082', 'e\u2081', 'e\u2082', 'e\u2083', 'A\u2081', 'A\u2082', 'A\u2083', 'RHS'];

function makeSimplexTable(bv, cb, tableau, title) {
  const W = 700;
  const BVW = 600; const CBW = 700; const RHSW = 900;
  const headerRow = simplexRow([
    { text: 'BV', bold: true, w: BVW, shade: 'DDDDDD' },
    { text: 'cB', bold: true, w: CBW, shade: 'DDDDDD' },
    ...varCols.map(v => ({ text: v, bold: true, w: v === 'RHS' ? RHSW : W, shade: 'DDDDDD' }))
  ]);

  const rows = [headerRow];
  for (let i = 0; i < bv.length; i++) {
    rows.push(simplexRow([
      { text: bv[i], w: BVW },
      { text: cb[i], w: CBW },
      ...tableau[i].map((v, j) => ({ text: v, w: j === 11 ? RHSW : W }))
    ]));
  }

  const totalW = BVW + CBW + W * 11 + RHSW - W + RHSW - RHSW + RHSW;
  return [
    new Paragraph({ spacing: { before: 120, after: 60 }, children: [new TextRun({ text: title, bold: true, italics: true, size: 22, font: "Times New Roman" })] }),
    new Table({
      width: { size: 9200, type: WidthType.DXA },
      rows
    })
  ];
}

