});

display_content.json_block:
{"language": "javascript", "code": "const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  Header, Footer, AlignmentType, HeadingLevel, BorderStyle, WidthType,
  ShadingType, VerticalAlign, PageNumber, LevelFormat, ExternalHyperlink,
  SectionType, Column
} = require('docx');
const fs = require('fs');

// ── Colour palette ──────────────────────────────────────────────────────────
const BLUE   = "1F497D";   // Elsevier-style dark blue
const LBLUE  = "D9E2F3";   // Light blue for table headers
const GREY   = "F2F2F2";   // Alternating row tint
const WHITE  = "FFFFFF";
const BLACK  = "000000";

// ── Reusable border / shading helpers ───────────────────────────────────────
const thinBorder = { style: BorderStyle.SINGLE, size: 4, color: "AAAAAA" };
const cellBorders = { top: thinBorder, bottom: thinBorder, left: thinBorder, right: thinBorder };

function hdrCell(text, w) {
  return new TableCell({
    width: { size: w, type: WidthType.DXA },
    borders: cellBorders,
    shading: { fill: BLUE, type: ShadingType.CLEAR },
    margins: { top: 80, bottom: 80, left: 120, right: 120 },
    verticalAlign: VerticalAlign.CENTER,
    children: [new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ text, bold: true, color: WHITE, size: 18, font: "Arial" })]
    })]
  });
}

function dataCell(text, w, shade = WHITE, bold = false, center = false) {
  return new TableCell({
    width: { size: w, type: WidthType.DXA },
    borders: cellBorders,
    shading: { fill: shade, type: ShadingType.CLEAR },
    margins: { top: 80, bottom: 80, left: 120, right: 120 },
    verticalAlign: VerticalAlign.CENTER,
    children: [new Paragraph({
      alignment: center ? AlignmentType.CENTER : AlignmentType.LEFT,
      children: [new TextRun({ text, size: 18, font: "Arial", bold, color: BLACK })]
    })]
  });
}

// ── Body paragraph helper ────────────────────────────────────────────────────
function body(text, opts = {}) {
  const runs = [];
  if (opts.indent) {
    // split on ** for inline bold
    const parts = text.split(/(\*\*[^*]+\*\*)/g);
    parts.forEach(p => {
      const m = p.match(/^\*\*(.+)\*\*$/);
      if (m) runs.push(new TextRun({ text: m[1], bold: true, size: 20, font: "Arial" }));
      else if (p) runs.push(new TextRun({ text: p, size: 20, font: "Arial" }));
    });
  } else {
    const parts = text.split(/(\*\*[^*]+\*\*)/g);
    parts.forEach(p => {
      const m = p.match(/^\*\*(.+)\*\*$/);
      if (m) runs.push(new TextRun({ text: m[1], bold: true, size: 20, font: "Arial" }));
      else if (p) runs.push(new TextRun({ text: p, size: 20, font: "Arial" }));
    });
  }
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { after: 120, line: 276 },
    indent: opts.indent ? { left: 360 } : undefined,
    children: runs
  });
}

function equation(text) {
  return new Paragraph({
    alignment: AlignmentType.CENTER,
    spacing: { before: 100, after: 100 },
    children: [new TextRun({ text, italics: true, size: 20, font: "Cambria Math" })]
  });
}

function caption(text) {
  return new Paragraph({
    alignment: AlignmentType.LEFT,
    spacing: { before: 60, after: 160 },
    children: [new TextRun({ text, bold: true, size: 18, font: "Arial", color: "444444" })]
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 240, after: 120 },
    children: [new TextRun({ text, bold: true, size: 24, font: "Arial", color: BLUE })]
  });
}

function h3(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_3,
    spacing: { before: 180, after: 80 },
    children: [new TextRun({ text, bold: true, italics: true, size: 21, font: "Arial", color: "2E4057" })]
  });
}

function bullet(text) {
  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  const runs = [];
  parts.forEach(p => {
    const m = p.match(/^\*\*(.+)\*\*$/);
    if (m) runs.push(new TextRun({ text: m[1], bold: true, size: 20, font: "Arial" }));
    else if (p) runs.push(new TextRun({ text: p, size: 20, font: "Arial" }));
  });
  return new Paragraph({
    numbering: { reference: "bullets", level: 0 },
    spacing: { after: 80 },
    children: runs
  });
}

function spacer(n = 1) {
  return Array.from({ length: n }, () =>
    new Paragraph({ children: [new TextRun({ text: "", size: 20 })] })
  );
}

// ────────────────────────────────────────────────────────────────────────────
// TABLE DEFINITIONS
// ────────────────────────────────────────────────────────────────────────────

// Table 1 – Comparison of related systems  (6 cols, total 9026 DXA for A4)
