const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  Header, Footer, AlignmentType, HeadingLevel, BorderStyle, WidthType,
  ShadingType, VerticalAlign, PageNumber, LevelFormat
} = require('docx');
const fs = require('fs');

const BLUE  = "1F497D";
const LBLUE = "D9E2F3";
const GREY  = "F2F2F2";
const WHITE = "FFFFFF";
const BLACK = "000000";

const thin = { style: BorderStyle.SINGLE, size: 4, color: "BBBBBB" };
const allBorders = { top: thin, bottom: thin, left: thin, right: thin };

function hCell(text, w) {
  return new TableCell({
    width: { size: w, type: WidthType.DXA }, borders: allBorders,
    shading: { fill: BLUE, type: ShadingType.CLEAR },
    margins: { top: 80, bottom: 80, left: 100, right: 100 },
    children: [new Paragraph({ alignment: AlignmentType.CENTER,
      children: [new TextRun({ text, bold: true, color: WHITE, size: 18, font: "Times New Roman" })] })]
  });
}

function dCell(text, w, shade = WHITE, bold = false, center = false) {
  return new TableCell({
    width: { size: w, type: WidthType.DXA }, borders: allBorders,
    shading: { fill: shade, type: ShadingType.CLEAR },
    margins: { top: 80, bottom: 80, left: 100, right: 100 },
    children: [new Paragraph({ alignment: center ? AlignmentType.CENTER : AlignmentType.LEFT,
      children: [new TextRun({ text, size: 18, font: "Times New Roman", bold, color: BLACK })] })]
  });
}

// Body paragraph — Times New Roman, justified, double-space feel
function p(text, extraSpacing = 0) {
  // handle **bold** inline
  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  const runs = parts.map(pt => {
    const m = pt.match(/^\*\*(.+)\*\*$/);
    return new TextRun(m
      ? { text: m[1], bold: true, size: 24, font: "Times New Roman" }
      : { text: pt, size: 24, font: "Times New Roman" });
  });
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { after: 160 + extraSpacing, line: 360 }, // double spaced
    indent: { firstLine: 720 }, // paragraph indent
    children: runs
  });
}

// No-indent version for abstract / lists
function pni(text) {
  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  const runs = parts.map(pt => {
    const m = pt.match(/^\*\*(.+)\*\*$/);
    return new TextRun(m
      ? { text: m[1], bold: true, size: 24, font: "Times New Roman" }
      : { text: pt, size: 24, font: "Times New Roman" });
  });
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { after: 140, line: 340 },
    children: runs
  });
}

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 360, after: 180 },
    children: [new TextRun({ text, bold: true, size: 28, font: "Times New Roman", color: BLACK, allCaps: true })]
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 280, after: 120 },
    children: [new TextRun({ text, bold: true, size: 26, font: "Times New Roman", color: BLACK })]
  });
}

function h3(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_3,
    spacing: { before: 200, after: 80 },
    children: [new TextRun({ text, bold: true, italics: true, size: 24, font: "Times New Roman", color: BLACK })]
  });
}

function bl(text) {
  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  const runs = parts.map(pt => {
    const m = pt.match(/^\*\*(.+)\*\*$/);
    return new TextRun(m
      ? { text: m[1], bold: true, size: 24, font: "Times New Roman" }
      : { text: pt, size: 24, font: "Times New Roman" });
  });
  return new Paragraph({
    numbering: { reference: "bullets", level: 0 },
    spacing: { after: 100, line: 320 },
    children: runs
  });
}

function cap(text) {
  return new Paragraph({
    spacing: { before: 120, after: 80 },
    children: [new TextRun({ text, bold: true, size: 22, font: "Times New Roman", italics: true })]
  });
}

function gap() {
  return new Paragraph({ children: [new TextRun({ text: " ", size: 24 })] });
}

// ─── TABLES ────────────────────────────────────────────────────────────────

function makeTable1() {
  const cols = [2200, 1300, 1300, 1300, 1300, 900];
  const TW = cols.reduce((a, b) => a + b, 0);
  const rows = [
    ["HireAI (Our System)", "✓", "✓", "✓", "✓", "2026"],
    ["Bharadwaj & Bhattacharyya [3]", "✓", "✗", "✗", "✗", "2022"],
    ["Li et al. [4]", "✓", "✗", "✗", "✗", "2022"],
    ["Raghavan et al. [5]", "✗", "✓", "✗", "✗", "2020"],
    ["Piacentino et al. [6]", "✗", "✗", "✓", "✗", "2022"],
    ["LinkedIn / Indeed", "✗", "✗", "✗", "✓", "—"],
  ];
  return new Table({
    width: { size: TW, type: WidthType.DXA }, columnWidths: cols,
    rows: [
      new TableRow({ children: [
        hCell("System", cols[0]), hCell("Semantic Match", cols[1]),
        hCell("Bias Mitigation", cols[2]), hCell("XAI", cols[3]),
        hCell("Real-Time Data", cols[4]), hCell("Year", cols[5])
      ]}),
      ...rows.map((r, i) => new TableRow({ children: r.map((c, j) =>
        dCell(c, cols[j], i % 2 === 0 ? WHITE : GREY, j === 0, j > 0)) }))
    ]
  });
}

function makeTable2() {
  const cols = [3000, 1600, 1600, 1600];
  const TW = cols.reduce((a, b) => a + b, 0);
  const rows = [
    ["Job title and description", "✓", "✓", "Both"],
    ["Required skills fields", "✓", "✓", "Both"],
    ["Application tracking", "✓", "✗", "Internal only"],
    ["ATS scoring", "✓", "✓", "Both"],
    ["Real-time availability", "✗", "✓", "External only"],
    ["Platform-controlled data", "✓", "✗", "Internal only"],
  ];
  return new Table({
    width: { size: TW, type: WidthType.DXA }, columnWidths: cols,
    rows: [
      new TableRow({ children: [
        hCell("Parameter", cols[0]), hCell("Internal DB", cols[1]),
        hCell("JSearch API", cols[2]), hCell("Available In", cols[3])
      ]}),
      ...rows.map((r, i) => new TableRow({ children: r.map((c, j) =>
        dCell(c, cols[j], i % 2 === 0 ? WHITE : GREY, false, j > 0)) }))
    ]
  });
}

function makeTable3() {
  const cols = [2400, 1600, 1700, 1700];
  const TW = cols.reduce((a, b) => a + b, 0);
  const rows = [
    ["Software Engineering", "87.3%", "85.1%", "Above Target"],
    ["Data Science", "85.1%", "84.0%", "At Target"],
    ["Product Management", "81.4%", "80.5%", "Near Target"],
    ["UI/UX Design", "83.6%", "82.1%", "Near Target"],
    ["DevOps", "86.2%", "85.8%", "Above Target"],
    ["Overall Average", "84.7%", "83.5%", "Near Target"],
  ];
  return new Table({
    width: { size: TW, type: WidthType.DXA }, columnWidths: cols,
    rows: [
