}

// Body paragraph — Times New Roman, justified, double-space feel
function p(text, extraSpacing = 0) {
  // handle **bold** inline
  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  const runs = parts.map(pt => {
    const m = pt.match(/^\*\*(.+)\*\*$/);
    return new TextRun(m
      ? { text: m[1], bold: true, size: 24, font: "Times New Roman" }
      : { text: pt, size: 24, font: "Times New Roman" });
  });
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { after: 160 + extraSpacing, line: 360 }, // double spaced
    indent: { firstLine: 720 }, // paragraph indent
    children: runs
  });
}

// No-indent version for abstract / lists
function pni(text) {
  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  const runs = parts.map(pt => {
    const m = pt.match(/^\*\*(.+)\*\*$/);
    return new TextRun(m
      ? { text: m[1], bold: true, size: 24, font: "Times New Roman" }
      : { text: pt, size: 24, font: "Times New Roman" });
  });
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { after: 140, line: 340 },
    children: runs
  });
}

function h1(text) {
