const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  Header, Footer, AlignmentType, HeadingLevel, BorderStyle, WidthType,
  ShadingType, VerticalAlign, PageNumber, LevelFormat, PageBreak
} = require('docx');
const fs = require('fs');

// ── Palette ─────────────────────────────────────────────────────────────────
const BLUE  = "003366";
const LBLUE = "D6E4F0";
const GREY  = "F5F5F5";
const WHITE = "FFFFFF";
const BLACK = "000000";
const CODE_BG = "F0F0F0";

// ── Border helpers ───────────────────────────────────────────────────────────
const thin = { style: BorderStyle.SINGLE, size: 4, color: "AAAAAA" };
const allB = { top: thin, bottom: thin, left: thin, right: thin };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noAllB = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

// ── Cell factories ───────────────────────────────────────────────────────────
function hCell(text, w) {
  return new TableCell({
    width: { size: w, type: WidthType.DXA }, borders: allB,
    shading: { fill: BLUE, type: ShadingType.CLEAR },
    margins: { top: 80, bottom: 80, left: 120, right: 120 },
    children: [new Paragraph({ alignment: AlignmentType.CENTER,
      children: [new TextRun({ text, bold: true, color: WHITE, size: 18, font: "Times New Roman" })] })]
  });
}
function dCell(text, w, shade = WHITE, bold = false, center = false) {
  return new TableCell({
    width: { size: w, type: WidthType.DXA }, borders: allB,
    shading: { fill: shade, type: ShadingType.CLEAR },
    margins: { top: 80, bottom: 80, left: 120, right: 120 },
    children: [new Paragraph({ alignment: center ? AlignmentType.CENTER : AlignmentType.LEFT,
      children: [new TextRun({ text, size: 18, font: "Times New Roman", bold, color: BLACK })] })]
  });
}

// ── Paragraph helpers ────────────────────────────────────────────────────────
function body(text) {
  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  const runs = parts.map(pt => {
    const m = pt.match(/^\*\*(.+)\*\*$/);
    return new TextRun(m
      ? { text: m[1], bold: true, size: 22, font: "Times New Roman" }
      : { text: pt, size: 22, font: "Times New Roman" });
  });
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { after: 160, line: 336 },
    indent: { firstLine: 720 },
    children: runs
  });
}

function bodyNoIndent(text) {
  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  const runs = parts.map(pt => {
    const m = pt.match(/^\*\*(.+)\*\*$/);
    return new TextRun(m
      ? { text: m[1], bold: true, size: 22, font: "Times New Roman" }
      : { text: pt, size: 22, font: "Times New Roman" });
  });
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { after: 140, line: 320 },
    children: runs
  });
}

// Code / pseudocode line
function codeLine(text, indent = 0) {
  return new Paragraph({
    spacing: { after: 0, line: 280 },
    indent: { left: 360 + indent * 360 },
    children: [new TextRun({ text, size: 18, font: "Courier New", color: "1A1A1A" })]
  });
}

// Algorithm box wrapper using a table
function algoBox(lines) {
  // lines: array of {text, indent}
  const children = lines.map(l => codeLine(l.text, l.indent || 0));
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [new TableRow({ children: [
      new TableCell({
        width: { size: 9360, type: WidthType.DXA },
        borders: allB,
        shading: { fill: CODE_BG, type: ShadingType.CLEAR },
        margins: { top: 120, bottom: 120, left: 240, right: 240 },
        children
      })
    ]})]
  });
}

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 400, after: 180 },
    children: [new TextRun({ text, bold: true, size: 26, font: "Times New Roman", allCaps: true })]
  });
}
function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 280, after: 120 },
    children: [new TextRun({ text, bold: true, italics: true, size: 22, font: "Times New Roman" })]
  });
}
function h3(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_3,
    spacing: { before: 200, after: 80 },
    children: [new TextRun({ text, bold: true, size: 22, font: "Times New Roman" })]
  });
}
function bl(text) {
  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  const runs = parts.map(pt => {
    const m = pt.match(/^\*\*(.+)\*\*$/);
    return new TextRun(m
      ? { text: m[1], bold: true, size: 22, font: "Times New Roman" }
      : { text: pt, size: 22, font: "Times New Roman" });
  });
  return new Paragraph({
    numbering: { reference: "bullets", level: 0 },
    spacing: { after: 100, line: 300 },
    children: runs
  });
}
function figCaption(text) {
  return new Paragraph({
    alignment: AlignmentType.CENTER,
    spacing: { before: 80, after: 200 },
    children: [new TextRun({ text, italics: true, size: 20, font: "Times New Roman" })]
  });
}
function tableCaption(text) {
  return new Paragraph({
    alignment: AlignmentType.CENTER,
    spacing: { before: 180, after: 80 },
    children: [new TextRun({ text, bold: true, size: 20, font: "Times New Roman" })]
  });
}
function gap(n = 1) {
  return Array.from({ length: n }, () => new Paragraph({
    spacing: { after: 0 },
    children: [new TextRun({ text: " ", size: 22 })]
  }));
}
function rule() {
  return new Paragraph({
    spacing: { before: 60, after: 60 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: BLUE, space: 2 } },
    children: [new TextRun({ text: "" })]
  });
}

// ── IMAGE PLACEHOLDER ────────────────────────────────────────────────────────
function imgPlaceholder(figNum, label) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA }, columnWidths: [9360],
    rows: [new TableRow({ children: [new TableCell({
      width: { size: 9360, type: WidthType.DXA },
      borders: allB,
      shading: { fill: "E8EEF4", type: ShadingType.CLEAR },
      margins: { top: 400, bottom: 400, left: 240, right: 240 },
      children: [new Paragraph({
        alignment: AlignmentType.CENTER,
        children: [new TextRun({ text: `[ INSERT FIGURE ${figNum} HERE: ${label} ]`, bold: true, size: 20, font: "Times New Roman", color: "5A6A7A", italics: true })]
      })]
    })]}) ]
  });
}

// ── TABLES ───────────────────────────────────────────────────────────────────
function makeTableI() {
  const cols = [2200, 2600, 4560]; const TW = cols.reduce((a,b)=>a+b,0);
  const rows = [
    ["Frontend",       "React 18, Vite, Redux Toolkit",         "UI, state management, client-side routing"],
    ["API Gateway",    "Node.js 20, Express.js",                "Authentication, business logic, routing"],
    ["AI Microservice","Python 3.11, FastAPI",                  "Resume parsing, XAI, matching, ranking"],
    ["Database",       "MongoDB Atlas",                         "Profiles, jobs, applications, sessions"],
    ["File Storage",   "Cloudinary CDN",                        "Resume storage, image hosting"],
    ["External APIs",  "JSearch (RapidAPI)",                    "LinkedIn / Indeed / Glassdoor aggregation"],
  ];
  return new Table({ width:{size:TW,type:WidthType.DXA}, columnWidths:cols,
    rows:[
      new TableRow({ children:[hCell("Layer",cols[0]),hCell("Technology",cols[1]),hCell("Responsibility",cols[2])] }),
      ...rows.map((r,i)=>new TableRow({ children:r.map((c,j)=>dCell(c,cols[j],i%2===0?WHITE:GREY)) }))
    ]
  });
}

function makeTableII() {
  const cols = [3600, 1800, 1800, 2160]; const TW = cols.reduce((a,b)=>a+b,0);
  const rows = [
    ["AI Inference Time (Match)",  "< 2s",  "1.4s avg",  "✓ PASS"],
    ["Resume Parsing Time",        "< 10s", "6.2s avg",  "✓ PASS"],
    ["Page Load Time",             "< 3s",  "1.8s avg",  "✓ PASS"],
    ["Search & Filter Response",   "< 2s",  "0.9s avg",  "✓ PASS"],
    ["Monthly Deployment Cost",    "$0",    "$0",        "✓ PASS"],
  ];
  return new Table({ width:{size:TW,type:WidthType.DXA}, columnWidths:cols,
    rows:[
      new TableRow({ children:[hCell("Metric",cols[0]),hCell("Target",cols[1]),hCell("Achieved",cols[2]),hCell("Status",cols[3])] }),
      ...rows.map((r,i)=>new TableRow({ children:r.map((c,j)=>dCell(c,cols[j],i%2===0?WHITE:GREY,false,j>0)) }))
    ]
  });
}

function makeTableIII() {
  const cols = [2600, 2600, 1800, 2360]; const TW = cols.reduce((a,b)=>a+b,0);
  const rows = [
    ["Semantic Engine",        "Synonym Matching Accuracy",       "≥ 85%",      "87.3% ✓"],
    ["ATS Scorer",             "Pearson Corr. (vs Manual)",       "> 0.80 r",   "0.84 r ✓"],
    ["Fairness-Aware Ranking", "Demographic Parity Ratio",        "> 0.80",     "0.83 ✓"],
    ["XAI Engine",             "User Comprehension (UAT)",        "≥ 80%",      "80% ✓"],
    ["Bias Detector",          "Gender-Coded Language Recall",    "> 90%",      "92.1% ✓"],
    ["Career Chatbot",         "User Relevance Rating",           "> 4.0 / 5.0","4.2 / 5.0 ✓"],
  ];
  return new Table({ width:{size:TW,type:WidthType.DXA}, columnWidths:cols,
    rows:[
