{"language": "javascript", "code": "const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  Header, Footer, AlignmentType, HeadingLevel, BorderStyle, WidthType,
  ShadingType, VerticalAlign, PageNumber, LevelFormat, PageBreak
} = require('docx');
const fs = require('fs');

// ── Palette ─────────────────────────────────────────────────────────────────
const BLUE  = "003366";
const LBLUE = "D6E4F0";
const GREY  = "F5F5F5";
const WHITE = "FFFFFF";
const BLACK = "000000";
const CODE_BG = "F0F0F0";

// ── Border helpers ───────────────────────────────────────────────────────────
const thin = { style: BorderStyle.SINGLE, size: 4, color: "AAAAAA" };
const allB = { top: thin, bottom: thin, left: thin, right: thin };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noAllB = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

// ── Cell factories ───────────────────────────────────────────────────────────
function hCell(text, w) {
  return new TableCell({
    width: { size: w, type: WidthType.DXA }, borders: allB,
    shading: { fill: BLUE, type: ShadingType.CLEAR },
    margins: { top: 80, bottom: 80, left: 120, right: 120 },
    children: [new Paragraph({ alignment: AlignmentType.CENTER,
      children: [new TextRun({ text, bold: true, color: WHITE, size: 18, font: "Times New Roman" })] })]
  });
}
function dCell(text, w, shade = WHITE, bold = false, center = false) {
  return new TableCell({
    width: { size: w, type: WidthType.DXA }, borders: allB,
    shading: { fill: shade, type: ShadingType.CLEAR },
    margins: { top: 80, bottom: 80, left: 120, right: 120 },
    children: [new Paragraph({ alignment: center ? AlignmentType.CENTER : AlignmentType.LEFT,
      children: [new TextRun({ text, size: 18, font: "Times New Roman", bold, color: BLACK })] })]
  });
}

// ── Paragraph helpers ────────────────────────────────────────────────────────
function body(text) {
  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  const runs = parts.map(pt => {
    const m = pt.match(/^\*\*(.+)\*\*$/);
    return new TextRun(m
      ? { text: m[1], bold: true, size: 22, font: "Times New Roman" }
      : { text: pt, size: 22, font: "Times New Roman" });
  });
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { after: 160, line: 336 },
    indent: { firstLine: 720 },
    children: runs
  });
}

function bodyNoIndent(text) {
  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  const runs = parts.map(pt => {
    const m = pt.match(/^\*\*(.+)\*\*$/);
