// ── ALGORITHM BOXES ──────────────────────────────────────────────────────────
function algoSemanticMatching() {
  return algoBox([
    {text: "Algorithm 1: Semantic Skill Matching Engine"},
    {text: "─────────────────────────────────────────────────────────────"},
    {text: "Input:  Resume text R, Job Description text J, ESCO graph G"},
    {text: "Output: ATS score S ∈ [0, 100], skill gap list Δ"},
    {text: "─────────────────────────────────────────────────────────────"},
    {text: "1.  skills_R ← ExtractSkills(R)           // SpaCy NER"},
    {text: "2.  skills_J ← ExtractSkills(J)           // SpaCy NER"},
    {text: "3.  matched ← [], unmatched ← []"},
    {text: "4.  FOR each skill s_j in skills_J DO"},
    {text: "5.      best_score ← 0", indent: 1},
    {text: "6.      FOR each skill s_r in skills_R DO", indent: 1},
    {text: "7.          // Step 1: Exact / fuzzy string match", indent: 2},
    {text: "8.          fuzzy_score ← FuzzyMatch(s_j, s_r)   // Levenshtein", indent: 2},
    {text: "9.          IF fuzzy_score ≥ 0.90 THEN best_score ← 1.0; BREAK", indent: 2},
    {text: "10.         // Step 2: ESCO graph adjacency check", indent: 2},
    {text: "11.         path ← ShortestPath(G, s_j, s_r)", indent: 2},
    {text: "12.         graph_score ← 1 / (1 + path_length(path))", indent: 2},
    {text: "13.         // Step 3: Embedding cosine similarity", indent: 2},
    {text: "14.         emb_score ← CosineSim(Embed(s_j), Embed(s_r))", indent: 2},
    {text: "15.         combined ← max(fuzzy_score, graph_score, emb_score)", indent: 2},
    {text: "16.         IF combined > best_score THEN best_score ← combined", indent: 2},
    {text: "17.     END FOR", indent: 1},
    {text: "18.     IF best_score ≥ threshold THEN matched.append(s_j)", indent: 1},
    {text: "19.     ELSE unmatched.append(s_j)", indent: 1},
    {text: "20. END FOR"},
    {text: "21. skill_score ← |matched| / |skills_J| × 100"},
    {text: "22. S ← w1 × skill_score + w2 × ExperienceScore(R,J) +"},
    {text: "             w3 × EducationScore(R,J)        // w1+w2+w3 = 1"},
    {text: "23. Δ ← unmatched  // skills the candidate is missing"},
    {text: "24. RETURN S, Δ"},
    {text: "─────────────────────────────────────────────────────────────"},
  ]);
}

function algoFAR() {
  return algoBox([
    {text: "Algorithm 2: Fairness-Aware Ranking (FAR)"},
    {text: "─────────────────────────────────────────────────────────────"},
    {text: "Input:  Candidate list C ranked by ATS score, threshold τ = 0.80"},
    {text: "Output: Re-ranked list C' satisfying DPR ≥ τ"},
    {text: "─────────────────────────────────────────────────────────────"},
    {text: "1.  shortlist ← [c ∈ C | c.score ≥ cutoff]"},
    {text: "2.  groups ← GroupByDemographic(shortlist)   // proxy inference"},
    {text: "3.  rates  ← {}"},
    {text: "4.  FOR each group g in groups DO"},
    {text: "5.      rates[g] ← |shortlisted in g| / |applicants in g|", indent: 1},
    {text: "6.  END FOR"},
    {text: "7.  max_rate ← max(rates.values())"},
    {text: "8.  DPR ← min(rates.values()) / max_rate"},
    {text: "9.  IF DPR ≥ τ THEN"},
    {text: "10.     RETURN C              // already fair — no change needed", indent: 1},
    {text: "11. ELSE"},
    {text: "12.     // Apply AIF360 Calibrated Equalized Odds post-processor", indent: 1},
    {text: "13.     C' ← AIF360_Rerank(C, privileged_group=max_rate_group,", indent: 1},
    {text: "                           unprivileged_groups=other_groups)", indent: 1},
    {text: "14.     // Verify new DPR meets threshold", indent: 1},
    {text: "15.     new_DPR ← ComputeDPR(C')", indent: 1},
    {text: "16.     IF new_DPR < τ THEN LOG warning('DPR target not met')", indent: 1},
    {text: "17.     RETURN C'", indent: 1},
    {text: "18. END IF"},
    {text: "─────────────────────────────────────────────────────────────"},
  ]);
}

function algoXAI() {
  return algoBox([
    {text: "Algorithm 3: Counterfactual XAI Explanation Generator"},
    {text: "─────────────────────────────────────────────────────────────"},
    {text: "Input:  Candidate score S, job threshold T, skill gap list Δ"},
    {text: "        Skill contribution weights W, LLM API endpoint"},
    {text: "Output: Natural language explanation E, top-3 recommendations R"},
    {text: "─────────────────────────────────────────────────────────────"},
    {text: "1.  IF S ≥ T THEN"},
    {text: "2.      RETURN 'Congratulations! You are in the shortlist.'", indent: 1},
    {text: "3.  END IF"},
    {text: "4.  gap ← T - S                // score improvement needed"},
    {text: "5.  ranked_gaps ← SortByMarginalImpact(Δ, W)"},
    {text: "6.  R ← [], cumulative_gain ← 0"},
    {text: "7.  FOR each missing_skill ms in ranked_gaps DO"},
    {text: "8.      gain ← W[ms] × 100", indent: 1},
    {text: "9.      R.append({skill: ms, projected_gain: gain})", indent: 1},
    {text: "10.     cumulative_gain += gain", indent: 1},
    {text: "11.     IF cumulative_gain ≥ gap OR |R| = 3 THEN BREAK", indent: 1},
    {text: "12. END FOR"},
    {text: "13. prompt ← BuildPrompt(S, T, R)  // structured LLM prompt"},
    {text: "14. E ← LLM_API.generate(prompt)   // GPT-4o-mini"},
    {text: "15. RETURN E, R"},
    {text: "─────────────────────────────────────────────────────────────"},
  ]);
}

function algoATS() {
  return algoBox([
    {text: "Algorithm 4: NLP Resume Parser & ATS Scorer"},
    {text: "─────────────────────────────────────────────────────────────"},
    {text: "Input:  Resume file F (PDF or DOCX), Job Description J"},
    {text: "Output: Structured profile P, ATS score S, suggestions L"},
    {text: "─────────────────────────────────────────────────────────────"},
    {text: "1.  IF FileType(F) = PDF  THEN text ← PyMuPDF.extract(F)"},
    {text: "2.  ELIF FileType(F) = DOCX THEN text ← python_docx.extract(F)"},
    {text: "3.  ELSE text ← Tesseract_OCR(F)   // scanned / image PDF"},
    {text: "4.  doc ← SpaCy_NLP_Pipeline(text)"},
    {text: "5.  P.name       ← NER_Entity(doc, 'PERSON')"},
    {text: "6.  P.skills     ← CustomSkillExtractor(doc)  // ESCO-trained"},
    {text: "7.  P.experience ← ParseWorkHistory(doc)"},
    {text: "8.  P.education  ← ParseEducation(doc)"},
    {text: "9.  // Weighted ATS scoring (weights configurable per job)"},
    {text: "10. S_skill  ← SemanticMatch(P.skills, J.skills) × 0.40"},
    {text: "11. S_exp    ← ExperienceScore(P.experience, J) × 0.25"},
    {text: "12. S_edu    ← EducationScore(P.education, J)   × 0.20"},
    {text: "13. S_format ← FormatComplianceScore(text)      × 0.10"},
    {text: "14. S_kw     ← KeywordDensityScore(text, J)     × 0.05"},
    {text: "15. S ← S_skill + S_exp + S_edu + S_format + S_kw"},
    {text: "16. L ← GenerateImprovements(P, J, S)"},
    {text: "17. RETURN P, S, L"},
    {text: "─────────────────────────────────────────────────────────────"},
  ]);
}

